class Solution(object):
    def binaryGap(self, n):
        last_pos = -1
        max_gap = 0
        pos = 0
        while n > 0:
            if n & 1:
                if last_pos != -1:
                    max_gap = max(max_gap, pos - last_pos)
                last_pos = pos
            pos += 1
            n >>= 1
        return max_gap
